import { ClassificationResult } from "@/lib/types";
import { classifyByRules } from "./ruleClassifier";
import { classifyWithAI } from "./aiClassifier";

export async function classifyDocument(
  text: string,
): Promise<ClassificationResult> {
  // Try rule-based classification first for speed
  const ruleResult = classifyByRules(text);

  if (ruleResult) {
    console.log("[v0] Using rule-based classification");
    return ruleResult;
  }

  // Fall back to AI classification
  console.log("[v0] Using AI-based classification with Groq");
  try {
    return await classifyWithAI(text);
  } catch (error) {
    console.error(
      "[v0] AI classification failed, defaulting to Others:",
      error,
    );
    // Fallback to Others category if AI fails
    return {
      category: "Others",
      confidence: 0.5,
      mode: "rule-based",
      reasoning: "Default fallback due to classification error",
    };
  }
}

export { classifyByRules, classifyWithAI };
